#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[15];
	int total;
};
student a[110];
int n;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%d%d",&(a[i].total));
		scanf("%s",a[i].name);
	}
	for(int i=n;i>=1;i--)
	{
		for(int j=1;j<=i;j++)
		{
			if(a[j].total<a[j+1].total)
			{
				swap(a[j],a[j+1]);
			}
		}
	}
	printf("%s",a[1].name);
	return 0;
}
